class Solution {
    public int lengthOfLongestSubstring(String s) {
        int n = s.length();
        int[] charCount = new int[256];

        int maxLen = 0;
        int start = 0;

        for (int i = 0; i < n; i++) {
            int charCode = s.charAt(i) - 'a'; // Convert character to its ASCII code
            if (charCount[charCode] != 0) {
                charCount[charCode]++;
            } else {
                start = Math.max(start, i - charCode); // Update start index if necessary
            }

            maxLen = Math.max(maxLen, i - start + 1);
        }

        return maxLen;
    }
}
```

